    for field_name in (
        "medications",
        "key_teaching_points",
        "time_critical_actions",
        "clinical_red_flags",
        "clinical_sources",
        "initial_labs",
    ):
        risk_text = f"{risk_text} {' '.join(_nested_strings(data.get(field_name))).lower()}"
    return any(_contains_safety_term(risk_text, term) for term in RENAL_RISK_TRIGGER_TERMS)


